+    fn build_lines_ledger_observation_entry() {
+        let data = VoiOverlayData {
+            title: "T".to_string(),
+            tick: None,
+            source: None,
+            posterior: sample_posterior(),
+            decision: None,
+            observation: None,
+            ledger: vec![VoiLedgerEntry::Observation {
+                sample_idx: 42,
+                violated: false,
+                posterior_mean: 0.789,
