+        let data = VoiOverlayData {
+            title: "T".to_string(),
+            tick: None,
+            source: None,
+            posterior: VoiPosteriorSummary {
+                alpha: 2.0,
+                beta: 3.0,
+                mean: 0.4,
+                variance: 0.04,
+                expected_variance_after: 0.03,
+                voi_gain: 0.01,
