+            decision: None,
+            observation: None,
+            ledger: Vec::new(),
+        };
+        let overlay = VoiDebugOverlay::new(data);
+        let lines = overlay.build_lines(50);
+        // VOI = Var[p] - E[Var|1] header
+        assert!(
+            lines.iter().any(|l| l.contains("VOI = Var[p] - E[Var|1]")),
